```cpp
#include <iostream>
#include <vector>
#include <stack>

using namespace std;

class Graph {
private:
    int V; // Number of vertices
    vector<int> *adj; // Pointer to an array containing adjacency lists

public:
    Graph(int V); // Constructor
    void addEdge(int v, int w); // Function to add an edge to the graph
    void DFSUtil(int v, bool visited[]); // A utility function used by DFS
    void DFS(int s); // DFS traversal of the vertices reachable from s
};

// Constructor
Graph::Graph(int V) {
    this->V = V;
    adj = new vector<int>[V];
}

// Function to add an edge to the graph
void Graph::addEdge(int v, int w) {
    adj[v].push_back(w); // Add w to v’s list.
}

// A utility function used by DFS
void Graph::DFSUtil(int v, bool visited[]) {
    // Mark the current node as visited and print it
    visited[v] = true;
    cout << v << " ";

    // Recur for all the vertices adjacent to this vertex
    for (int i = 0; i < adj[v].size(); ++i) {
        if (!visited[adj[v][i]])
            DFSUtil(adj[v][i], visited);
    }
}

// DFS traversal of the vertices reachable from s
void Graph::DFS(int s) {
    // Mark all the vertices as not visited
    bool *visited = new bool[V];
    for (int i = 0; i < V; ++i)
        visited[i] = false;

    // Call the recursive helper function to print DFS traversal
    DFSUtil(s, visited);
}

// Driver code
int main() {
    // Create a graph given in the above diagram
    Graph g(4);
    g.addEdge(0, 1);
    g.addEdge(0, 2);
    g.addEdge(1, 2);
    g.addEdge(2, 0);
    g.addEdge(2, 3);
    g.addEdge(3, 3);

    cout << "Following is Depth First Traversal (starting from vertex 2) \n";
    g.DFS(2);

    return 0;
}
```

### Explanation:
1. **Graph Class**:
   - `V`: Number of vertices.
   - `adj`: Pointer to an array containing adjacency lists.

2. **Constructor (`Graph::Graph(int V)`)**:
   - Initializes the graph with `V` vertices and creates an empty adjacency list for each vertex.

3. **Add Edge (`Graph::addEdge(int v, int w)`)**:
   - Adds an edge from vertex `v` to vertex `w`.

4. **DFS Utility Function (`Graph::DFSUtil(int v, bool visited[])`)**:
   - Marks the current node as visited and prints it.
   - Recursively visits all adjacent vertices that have not been visited.

5. **DFS Traversal (`Graph::DFS(int s)`)**:
   - Initializes a boolean array to keep track of visited nodes.
   - Calls `DFSUtil` starting from vertex `s`.

6. **Main Function**:
   - Creates a graph and performs DFS traversal starting from vertex 2.

This code provides a basic implementation of DFS in C++. You can modify it according to your specific requirements, such as handling directed or undirected graphs, using different data structures for adjacency lists, etc.

